package com.fortinet.nac.ingestion.util;

import com.fortinet.nac.ingestion.dto.EntityStateDisplayDTO;
import lombok.RequiredArgsConstructor;
import org.redisson.api.RBucket;
import org.redisson.api.RMap;
import org.redisson.api.RedissonClient;
import org.springframework.stereotype.Component;

import java.util.concurrent.TimeUnit;

/**
 * Dedicated to managing Entity-exist cache and TTL operations
 */
@Component
@RequiredArgsConstructor
public class EntityCache {

    private final RedissonClient redissonClient;

    private static final String DISPLAY_VIEW_MAP_NAME = "entity:display:view";

    /**
     * Write into entity-exist cache
     */
    public void cacheEntityId(String key, Long entityId, int ttl) {
        // RBucket.set() may throw exceptions at least in the following cases:
        //   1. Redis is down or the connection pool is exhausted
        //   2. Network jitter causing timeouts
        //   3. Redis runs out of memory (OOM)
        RBucket<String> bucket = redissonClient.getBucket(key);
        bucket.set(entityId.toString(), ttl, TimeUnit.SECONDS);
    }

    /**
     * Clear all entity-exist cache entries.
     * Assumes this Redis database is dedicated to entity caching.
     * If Redis is shared, use deleteByPattern with a key prefix instead.
     */
    public void clear() {
        redissonClient.getKeys().flushdb();
    }

    /**
     * Query entity-exist cache
     */
    public Long getCachedEntityId(String key) {
        try {
            RBucket<String> bucket = redissonClient.getBucket(key);
            String val = bucket.get();
            return (val == null || val.isEmpty()) ? null : Long.parseLong(val);
        } catch (NumberFormatException e) {
            return null;
        }
    }

    /**
     * Cache entity display view (DTO for presentation layer)
     * @param key the entity identity key
     * @param dto display DTO object
     * @param ttl time-to-live in seconds
     */
    public void cacheDisplayView(String key, EntityStateDisplayDTO dto, int ttl) {
        RMap<String, EntityStateDisplayDTO> map = redissonClient.getMap(DISPLAY_VIEW_MAP_NAME);
        map.put(key, dto);
        // Set expiration for the specific entry
        map.expire(ttl, TimeUnit.SECONDS);
    }

    /**
     * Query cached entity display view
     * @param key the entity identity key
     * @return EntityStateDisplayDTO or null if not found
     */
    public EntityStateDisplayDTO getCachedDisplayView(String key) {
        try {
            RMap<String, EntityStateDisplayDTO> map = redissonClient.getMap(DISPLAY_VIEW_MAP_NAME);
            return map.get(key);
        } catch (Exception e) {
            return null;
        }
    }

    /**
     * Update display status field in cached display view
     * @param key the entity identity key
     * @param displayStatus new display status value
     */
    public void updateDisplayViewStatus(String key, String displayStatus) {
        try {
            RMap<String, EntityStateDisplayDTO> map = redissonClient.getMap(DISPLAY_VIEW_MAP_NAME);
            EntityStateDisplayDTO dto = map.get(key);
            if (dto != null) {
                dto.setDisplayStatus(displayStatus);
                map.put(key, dto);
            }
        } catch (Exception e) {
            // Silent failure - cache update failures should not affect business logic
        }
    }

    /**
     * Remove entity display view from cache
     * @param key the entity identity key
     */
    public void removeDisplayView(String key) {
        try {
            RMap<String, EntityStateDisplayDTO> map = redissonClient.getMap(DISPLAY_VIEW_MAP_NAME);
            map.remove(key);
        } catch (Exception e) {
            // Silent failure
        }
    }
}

