package com.fortinet.nac.ingestion.consumer.handler;

import com.fortinet.nac.common.Constants;
import com.fortinet.nac.common.dto.IngestionRequest;
import com.fortinet.nac.common.redis.DistributedLock;
import com.fortinet.nac.common.service.IdService;
import com.fortinet.nac.common.util.StatusOr;
import com.fortinet.nac.ingestion.consumer.FingerprintBuildResult;
import com.fortinet.nac.ingestion.consumer.statemachine.EntityStateMachine;
import com.fortinet.nac.ingestion.consumer.EntityAttributeFingerprintBuilder;

import com.fortinet.nac.ingestion.delayqueue.RedisDelayQueueUtil;
import com.fortinet.nac.ingestion.entity.Entity;
import com.fortinet.nac.common.enums.EntityStage;
import com.fortinet.nac.common.enums.EntityType;
import com.fortinet.nac.ingestion.service.EntityService;
import com.fortinet.nac.ingestion.util.EntityCache;
import com.fortinet.nac.ingestion.util.RedisUtil;

import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Qualifier;
import org.springframework.stereotype.Component;

import java.time.Instant;

@Slf4j
@Component
@RequiredArgsConstructor
public class NewEntityHandler {

    private final EntityService entityService;
    private final EntityCache entityCache;
    private final DistributedLock distributedLock;
    private final EntityStateMachine stateMachine;
    private final EntityAttributeFingerprintBuilder entityAttributeFingerprintBuilder;

    @Qualifier("IngestionIdService")
    private final IdService idService;

    private final RedisDelayQueueUtil redisDelayQueueUtil;

    private static final int MAX_REQUEUE = 5;

    public StatusOr<Entity> handle(IngestionRequest req) {
        // 1. build fingerprint
        FingerprintBuildResult fpResult = entityAttributeFingerprintBuilder.build(req);
        StatusOr<Void> validation = validateRefExists(req, fpResult);
        if (!validation.ok()) {
            return StatusOr.error(validation.getStatus().getCode(), validation.getStatus().getMessage());
        }

        String fp = fpResult.getFingerprint();

        // 2. create new entity
        Instant now = Instant.now();

        Entity entity = Entity.builder()
                .id(idService.nextId())
                .type(EntityType.valueOf(req.getEntityType()))
                .source(req.getSource())
                .userId(req.getUserId())
                .hostId(req.getHostId())
                .adapterId(req.getAdapterId())
                .userIdentity(buildUserIdentity(req))
                .hostIdentity(buildHostIdentity(req))
                .processingStage(EntityStage.PENDING.toString())
                .processingCode(0)
                .attributeFingerprint(fp)
                .lastReqVersion(req.getVersion())
                .interrupted(false)
                .createdAt(now)
                .updatedAt(now)
                .build();

        entityService.save(entity);
        log.info("Entity DB data created");

        // 3. cache entityId
        String key = RedisUtil.getExistKey(req);
        try {
            // DB is the source of truth; the cache is used only for performance optimization.
            // Cache write failures should not fail the entire ingestion flow.
            entityCache.cacheEntityId(key, entity.getId(), Constants.RedisKeys.ENTITY_EXIST_KEY_TTL);
        } catch (Exception ex) {
            log.warn("Failed to cache entityId, degrade to DB lookup next time. key={}, entityId={}, err={}",
                     key, entity.getId(), ex.toString());
        }

        // 4. acquire processLock
        String processLockKey = RedisUtil.getEntityLockKey(Constants.RedisKeys.ENTITY_PROCESS_LOCK_PREFIX, req);
        // Immediately after entity is created, another request may already
        // be processing the same entity (e.g., due to a cache hit and winning the processLock).
        StatusOr<String> lock = acquireProcessLockOrRequeue(req, entity.getId(), processLockKey);
        if (!lock.ok()) return StatusOr.error(lock.getStatus().getCode(), lock.getStatus().getMessage());

        try {
            return stateMachine.start(req.getRequestId(), req.isAsync(), entity);
        } finally {
            distributedLock.unLock(processLockKey);
        }
    }

    private StatusOr<String> acquireProcessLockOrRequeue(IngestionRequest req, long entityId, String processLockKey) {
        // quick retry in 1~2s
        boolean acquired = false;
        for (int i = 0; i < 10; i++) {
            acquired = distributedLock.tryLock(processLockKey, Constants.RedisKeys.ENTITY_PROCESS_LOCK_TTL);
            if (acquired) return StatusOr.ok(processLockKey);
            sleep(150);
        }

        // requeue, due to acquire process lock failed
        log.warn("Cannot obtain processLock after creating db entity, begin requeue. entityId={}, key={}", entityId, processLockKey);

        int retryCount = req.getRequeueCount();
        if (retryCount >= MAX_REQUEUE) {
            return StatusOr.error(Constants.BusinesCode.ACQUIRE_PROCESS_LOCK_FAILURE_AFTER_ENTITY_CREATED,
                    "process lock fail after create, exceeded max retry");
        }

        long delaySeconds = 2L << retryCount;
        req.setRequeueCount(retryCount + 1);

        try {
            redisDelayQueueUtil.enqueueWithDelay(req, delaySeconds * 1000);
        } catch (Exception ex) {
            log.error("Failed to enqueue delay queue, will retry via stream. entityId={}, err={}",
                    entityId, ex.toString());
            // INTERNAL_ERROR will trigger consumer retry
            return StatusOr.error(Constants.BusinesCode.INTERNAL_ERROR, "delay enqueue failed");
        }

        return StatusOr.error(Constants.BusinesCode.ACQUIRE_PROCESS_LOCK_FAILURE_AFTER_ENTITY_CREATED,
                "process lock busy, request requeued");
    }

    private String buildHostIdentity(IngestionRequest req) {
        return req.getHostId() + "_" + req.getAdapterId();
    }

    private String buildUserIdentity(IngestionRequest req) {
        if (EntityType.USER_HOST_BINDING.toString().equals(req.getEntityType())) {
            return req.getUserId();
        }
        return null;
    }

    void sleep(long ms) {
        try {
            Thread.sleep(ms);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt(); // restore interrupt flag
        }
    }

    private StatusOr<Void> validateRefExists(IngestionRequest req, FingerprintBuildResult r) {
        EntityType type = EntityType.valueOf(req.getEntityType().toUpperCase());

        String providedFp = req.getAttributeFingerprint();
        // 1. If a fingerprint is provided in request, skip validation of referenced entities
        if (providedFp != null && !providedFp.isBlank()) {
            return StatusOr.ok(null);
        }

        // 2. Verify that the referenced entity exists in the database
        if (r.getHostAttribute() == null) {
            log.error(
                    "Validation failed: host not found. entityType={}, hostId={}, userId={}, adapterId={}, requestId={}",
                    req.getEntityType(), req.getHostId(), req.getUserId(),
                    req.getAdapterId(), req.getRequestId());
            return StatusOr.error(Constants.BusinesCode.HOST_NOT_FOUND,
                    "hostId not found: " + req.getHostId());
        }

        if (r.getDynamicClientAttribute() == null) {
            log.error(
                    "Validation failed: adapter not found. entityType={}, hostId={}, userId={}, adapterId={}, requestId={}",
                    req.getEntityType(), req.getHostId(), req.getUserId(),
                    req.getAdapterId(), req.getRequestId());
            return StatusOr.error(Constants.BusinesCode.ADAPTER_NOT_FOUND,
                    "adapterId not found: " + req.getAdapterId());
        }

        if (type == EntityType.USER_HOST_BINDING && r.getUserAttribute() == null) {
            log.error(
                    "Validation failed: user not found. entityType={}, hostId={}, userId={}, adapterId={}, requestId={}",
                    req.getEntityType(), req.getHostId(), req.getUserId(),
                    req.getAdapterId(), req.getRequestId());
            return StatusOr.error(Constants.BusinesCode.USER_NOT_FOUND,
                    "userId not found: " + req.getUserId());
        }

        return StatusOr.ok(null);
    }
}

